public class WorkflowDefinitionConfiguration : IEntityTypeConfiguration<WorkflowDefinition>
{
    public void Configure(EntityTypeBuilder<WorkflowDefinition> entity)
    {
        entity.ToTable("WorkflowDefinitions", "actions");
        entity.HasKey(e => e.Id);
        entity.ConfigureTrackedEntity();
        entity.ConfigureTenantEntity();

        entity.Property(e => e.Code).HasMaxLength(50).IsRequired();
        entity.Property(e => e.Version).IsConcurrencyToken();

        // Relationships
        entity.HasMany(e => e.States)
            .WithOne(s => s.WorkflowDefinition)
            .HasForeignKey(s => s.WorkflowDefinitionId)
            .OnDelete(DeleteBehavior.Cascade);

        entity.HasMany(e => e.Translations)
            .WithOne(t => t.WorkflowDefinition)
            .HasForeignKey(t => t.WorkflowDefinitionId)
            .OnDelete(DeleteBehavior.Cascade);

        // Indexes
        entity.HasIndex(e => new { e.TenantId, e.Code }).IsUnique();
    }
}

