// Features/Admin/Workflows/Shared/Mappers/WorkflowEntityMapper.cs

public class WorkflowEntityMapper(
    IDbContextFactory<ActionsDbContext> dbContextFactory,
    TranslationService translationService)
{
    public async Task<EntityMapperResult<WorkflowDefinition>> MapAsync(
        List<SaveWorkflowRequest> dtoList, Guid userId,
        Guid requestLanguageId, Guid defaultLanguageId,
        CancellationToken ct, ActionsDbContext? db = null)
    {
        var disposeDb = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            var result = new EntityMapperResult<WorkflowDefinition>();
            var now = DateTime.UtcNow;

            foreach (var dto in dtoList)
            {
                var existing = dto.Id != Guid.Empty
                    ? await db.WorkflowDefinitions.FindAsync([dto.Id], ct)
                    : null;

                if (existing is null)
                {
                    // CREATE
                    var entity = new WorkflowDefinition
                    {
                        Id = Guid.CreateVersion7(),
                        Code = dto.Code,
                        IsActive = true,
                        CreatedDate = now,
                        CreatedById = userId,
                    };

                    translationService.AddOrUpdateEntityTranslation(
                        entity, requestLanguageId, dto.Name, dto.Description);

                    result.NewItems.Add(entity);
                }
                else
                {
                    // UPDATE
                    existing.IsActive = dto.IsActive;
                    existing.UpdatedDate = now;
                    existing.UpdatedById = userId;
                    // Code is immutable after creation — not mapped on update

                    translationService.AddOrUpdateEntityTranslation(
                        existing, requestLanguageId, dto.Name, dto.Description);

                    result.UpdatedItems.Add(existing);
                }
            }

            return result;
        }
        finally
        {
            if (disposeDb) await db.DisposeAsync();
        }
    }

    // Single-DTO convenience overload
    public Task<EntityMapperResult<WorkflowDefinition>> MapAsync(
        SaveWorkflowRequest dto, Guid userId,
        Guid requestLanguageId, Guid defaultLanguageId,
        CancellationToken ct, ActionsDbContext? db = null)
        => MapAsync([dto], userId, requestLanguageId, defaultLanguageId, ct, db);
}

