public class WorkflowDTOMapper(TranslationService translationService)
{
    public WorkflowDefinitionDTO Map(
        WorkflowDefinition entity,
        Guid requestLanguageId,
        Guid defaultLanguageId)
    {
        var translation = translationService.GetEntityTranslation(
            entity, requestLanguageId, defaultLanguageId);

        return new WorkflowDefinitionDTO
        {
            Id = entity.Id,
            Name = translation.Name,
            Description = translation.Description,
            Code = entity.Code,
            IsActive = entity.IsActive,
            States = entity.States
                .Select(s => MapState(s, requestLanguageId, defaultLanguageId))
                .OrderBy(s => s.SortOrder)
                .ToList(),
            TranslatedNames = translationService.BuildTranslatedValues(
                entity.Translations, requestLanguageId, t => t.Name),
            TranslatedDescriptions = translationService.BuildTranslatedValues(
                entity.Translations, requestLanguageId, t => t.Description),
            ActionCount = entity.Actions.Count,
            Version = entity.Version,
            CreatedDate = entity.CreatedDate,
            UpdatedDate = entity.UpdatedDate,
        };
    }

    public List<WorkflowDefinitionGridItemDTO> MapGridItem(
        IList<WorkflowDefinition> entities,
        Guid requestLanguageId,
        Guid defaultLanguageId)
    {
        return entities.Select(entity =>
        {
            var translation = translationService.GetEntityTranslation(
                entity, requestLanguageId, defaultLanguageId);
            return new WorkflowDefinitionGridItemDTO
            {
                Id = entity.Id,
                Name = translation.Name,
                Code = entity.Code,
                IsActive = entity.IsActive,
                StateCount = entity.States.Count,
                ActionCount = entity.Actions.Count,
            };
        }).ToList();
    }

    private WorkflowStateDTO MapState(
        WorkflowState state,
        Guid requestLanguageId,
        Guid defaultLanguageId)
    {
        var translation = translationService.GetEntityTranslation(
            state, requestLanguageId, defaultLanguageId);
        return new WorkflowStateDTO
        {
            Id = state.Id,
            Name = translation.Name,
            Description = translation.Description,
            IsInitial = state.IsInitial,
            IsFinal = state.IsFinal,
            SortOrder = state.SortOrder,
        };
    }
}

