public class WorkflowQueryParameters : PagedQueryParameters<WorkflowDefinition>
{
    public string? Search { get; private set; }
    public bool? IsActive { get; private set; }

    public WorkflowQueryParameters WithSearch(string? search)
    {
        Search = search;
        return this;
    }

    public WorkflowQueryParameters WithIsActive(bool? isActive)
    {
        IsActive = isActive;
        return this;
    }

    public override IQueryable<WorkflowDefinition> ApplyFilters(
        IQueryable<WorkflowDefinition> query)
    {
        query = base.ApplyFilters(query);

        if (!string.IsNullOrWhiteSpace(Search))
        {
            var escaped = EscapeILike(Search);
            query = query.Where(w =>
                w.Translations.Any(t => EF.Functions.ILike(t.Name, $"%{escaped}%"))
                || EF.Functions.ILike(w.Code, $"%{escaped}%"));
        }

        if (IsActive.HasValue)
            query = query.Where(w => w.IsActive == IsActive.Value);

        return query;
    }

    public virtual IQueryable<WorkflowDefinition> IncludeRelations(
        IQueryable<WorkflowDefinition> query)
    {
        return query
            .Include(w => w.States)
            .Include(w => w.Translations);
    }
}

