public class GetWorkflowQuery(IDbContextFactory<ActionsDbContext> dbContextFactory)
{
    public async Task<WorkflowDefinition?> ExecuteAsync(
        Guid id, CancellationToken ct, ActionsDbContext? db = null)
    {
        var shouldDisposeContext = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            return await db.WorkflowDefinitions
                .AsNoTracking()
                .AsSplitQuery()
                .TagWith("GetWorkflowQuery")
                .Include(w => w.Translations)
                .Include(w => w.States).ThenInclude(s => s.Translations)
                .Include(w => w.States).ThenInclude(s => s.TransitionsFrom)
                .FirstOrDefaultAsync(w => w.Id == id, ct);
        }
        finally
        {
            if (shouldDisposeContext) await db.DisposeAsync();
        }
    }
}

// Features/Admin/Workflows/Shared/Queries/GetWorkflowsQuery.cs
public class GetWorkflowsQuery(IDbContextFactory<ActionsDbContext> dbContextFactory)
{
    public async Task<List<WorkflowDefinition>> ExecuteAsync(
        WorkflowQueryParameters parameters, CancellationToken ct)
    {
        await using var db = await dbContextFactory.CreateDbContextAsync(ct);

        var query = db.WorkflowDefinitions
            .AsSplitQuery()
            .TagWith("GetWorkflowsQuery");

        query = parameters.IncludeRelations(query);
        query = parameters.ApplyFilters(query);

        return await query
            .OrderBy(w => w.Code).ThenBy(w => w.Id)
            .ApplyPagination(parameters)
            .ToListAsync(ct);
    }
}

