// Features/Admin/Workflows/Shared/Commands/SaveWorkflowCommand.cs

public class SaveWorkflowCommand(
    IDbContextFactory<ActionsDbContext> dbContextFactory,
    WorkflowEntityMapper entityMapper,
    ILogger<SaveWorkflowCommand> logger)
{
    public async Task<CommandResult<EntityMapperResult<WorkflowDefinition>>> ExecuteAsync(
        SaveWorkflowRequest request, Guid userId,
        Guid requestLanguageId, Guid defaultLanguageId,
        CancellationToken ct, ActionsDbContext? db = null)
    {
        var shouldDisposeContext = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            // Step 1: EntityMapper handles create/update detection and field mapping
            var mapResult = await entityMapper.MapAsync(
                [request], userId, requestLanguageId, defaultLanguageId, ct, db);

            // Step 2: Check for empty result (entity not found on update)
            if (mapResult.NewItems.Count == 0 && mapResult.UpdatedItems.Count == 0)
                return CommandResult<EntityMapperResult<WorkflowDefinition>>.Fail(
                    "WORKFLOW-001", $"Workflow with ID '{request.Id}' not found.", 404);

            var isNew = mapResult.NewItems.Count > 0;
            var entity = isNew ? mapResult.NewItems[0] : mapResult.UpdatedItems[0];
            var workflowId = entity.Id;

            // Step 3: AddRange for new entities
            if (isNew)
                await db.WorkflowDefinitions.AddAsync(entity, ct);

            // Step 4: Protection checks (immutable Code on update)
            if (!isNew && !string.Equals(entity.Code, request.Code, StringComparison.OrdinalIgnoreCase))
                return CommandResult<EntityMapperResult<WorkflowDefinition>>.Fail(
                    "WORKFLOW-003", "Workflow code cannot be changed after creation.", 422);

            // Step 5: Uniqueness check (eager, DB index is final guard)
            if (isNew && await db.WorkflowDefinitions
                    .AnyAsync(w => w.Code == request.Code, ct))
                return CommandResult<EntityMapperResult<WorkflowDefinition>>.Fail(
                    "WORKFLOW-002", $"A workflow with code '{request.Code}' already exists.", 409);

            // Step 5: Child diffing (inline, NOT in mapper)
            var existingStates = isNew
                ? []
                : await db.WorkflowStates
                    .Where(s => s.WorkflowDefinitionId == workflowId)
                    .ToListAsync(ct);

            var incomingStateIds = request.States
                .Where(s => s.Id != Guid.Empty)
                .Select(s => s.Id)
                .ToHashSet();

            var statesToDelete = existingStates
                .Where(s => !incomingStateIds.Contains(s.Id))
                .ToList();
            var statesToAdd = request.States
                .Where(s => s.Id == Guid.Empty)
                .ToList();
            var statesToUpdate = request.States
                .Where(s => s.Id != Guid.Empty && existingStates.Any(e => e.Id == s.Id))
                .ToList();

            // Step 7: Business validation
            var hasInitialState = request.States.Any(s => s.IsInitial);
            if (!hasInitialState)
                return CommandResult<EntityMapperResult<WorkflowDefinition>>.Fail(
                    "WORKFLOW-004", "Workflow must have at least one initial state.", 422);

            // Step 7: Process children (add, update, remove)
            db.WorkflowStates.RemoveRange(statesToDelete);

            foreach (var stateReq in statesToAdd)
            {
                var newState = new WorkflowState
                {
                    Id = Guid.CreateVersion7(),
                    WorkflowDefinitionId = workflowId,
                    TenantId = entity.TenantId,
                    IsInitial = stateReq.IsInitial,
                    IsFinal = stateReq.IsFinal,
                    SortOrder = stateReq.SortOrder,
                    CreatedDate = DateTime.UtcNow,
                    CreatedById = userId,
                };
                // Handle state translations...
                await db.WorkflowStates.AddAsync(newState, ct);
            }

            foreach (var stateReq in statesToUpdate)
            {
                var existing = existingStates.First(s => s.Id == stateReq.Id);
                existing.IsInitial = stateReq.IsInitial;
                existing.IsFinal = stateReq.IsFinal;
                existing.SortOrder = stateReq.SortOrder;
                existing.UpdatedDate = DateTime.UtcNow;
                existing.UpdatedById = userId;
            }

            // Step 9: Save with TOCTOU protection
            try
            {
                await db.SaveChangesAsync(ct);
            }
            catch (DbUpdateException ex) when (
                ex.InnerException?.Message.Contains("ix_workflowdefinitions_code",
                    StringComparison.OrdinalIgnoreCase) == true)
            {
                return CommandResult<EntityMapperResult<WorkflowDefinition>>.Fail(
                    "WORKFLOW-002", $"A workflow with code '{request.Code}' already exists.", 409);
            }

            // Step 10: Post-save side effects (best-effort, each in try/catch)
            try
            {
                // Cache invalidation example
                logger.LogDebug("Workflow {WorkflowId} saved successfully", workflowId);
            }
            catch (Exception ex)
            {
                logger.LogWarning(ex, "Failed post-save side effect for workflow {WorkflowId}",
                    workflowId);
            }

            return CommandResult<EntityMapperResult<WorkflowDefinition>>.Ok(mapResult);
        }
        finally
        {
            if (shouldDisposeContext) await db.DisposeAsync();
        }
    }
}

