// Features/Admin/Workflows/Save/SaveWorkflowEndpoint.cs
public sealed class SaveWorkflowEndpoint(
    SaveWorkflowCommand saveCommand,
    AuditService auditService)
    : TenantEndpoint<SaveWorkflowRequest, SaveWorkflowResponse>
{
    public override void Configure()
    {
        Post("/api/v1/admin/workflows");
        Policies(ActionConstants.PolicyNames.WorkflowAdmin);
    }

    protected override async Task HandleValidatedRequestAsync(
        SaveWorkflowRequest req, CancellationToken ct)
    {
        var result = await saveCommand.ExecuteAsync(
            req, UserId, RequestLanguageId, DefaultLanguageId, ct);

        var isNew = result.NewItems.Count > 0;
        var entity = isNew ? result.NewItems[0] : result.UpdatedItems[0];

        var eventName = isNew ? "workflow.created" : "workflow.updated";
        await auditService.LogAsync(eventName, "WorkflowDefinition", entity.Id,
            new { req.Name, req.Code }, ct);

        if (isNew)
            await Send.CreatedAtAsync<GetWorkflowEndpoint>(
                new { id = entity.Id },
                new SaveWorkflowResponse(entity.Id), cancellation: ct);
        else
            await Send.OkAsync(new SaveWorkflowResponse(entity.Id), ct);
    }
}

