            (await dataTask).ToList(), RequestLanguageId, DefaultLanguageId);

        await Send.OkAsync(
            new GridListResponse<WorkflowDefinitionGridItemDTO>(
                items, await countTask, req.Page, req.PageSize),
            ct);
    }
}

// Features/Admin/Workflows/Delete/DeleteWorkflowEndpoint.cs
public sealed class DeleteWorkflowEndpoint(
    DeleteWorkflowCommand deleteCommand,
    AuditService auditService)
    : TenantEndpoint<DeleteWorkflowsRequest>
{
    public override void Configure()
    {
        Post("/api/v1/admin/workflows/delete");
        Policies(ActionConstants.PolicyNames.WorkflowAdmin);
    }

    protected override async Task HandleValidatedRequestAsync(
        DeleteWorkflowsRequest req, CancellationToken ct)
    {
        var result = await deleteCommand.ExecuteAsync(req.EntityKeys, ct);
        if (!result.Succeeded)
        {
            await SendProblemAsync(result.Error!.Code, result.Error.StatusCode, result.Error.Message, ct);
            return;
        }

        foreach (var key in req.EntityKeys)
            await auditService.LogAsync("workflow.deleted", "WorkflowDefinition", key, new { }, ct);

        await Send.NoContentAsync(ct);
    }
}

// Features/Admin/Workflows/Save/SaveWorkflowRequestValidator.cs
public class SaveWorkflowRequestValidator : Validator<SaveWorkflowRequest>
{
    public SaveWorkflowRequestValidator()
    {
        RuleFor(x => x.Name).NotEmpty().MaximumLength(255);
        RuleFor(x => x.Code).NotEmpty().MaximumLength(50)
            .Matches("^[A-Z0-9-]+$").WithMessage("Code: uppercase letters, numbers, hyphens only.");
        RuleForEach(x => x.States).ChildRules(state =>
        {
            state.RuleFor(s => s.Name).NotEmpty().MaximumLength(255);
            state.RuleFor(s => s.SortOrder).GreaterThanOrEqualTo(0);
        });
    }
}

